            .iter()
            .filter_map(|m| {
                // Accept chatId from full-scan or chat/chat_id fallbacks on DOM rows.
                let chat_id = m
                    .get("chatId")
                    .or_else(|| m.get("chat"))
                    .or_else(|| m.get("chat_id"))
                    .and_then(|v| v.as_str())
                    .filter(|s| !s.is_empty())?
                    .to_string();
                let body = m
                    .get("body")
                    .and_then(|v| v.as_str())
                    .map(|s| s.trim())
                    .unwrap_or("");
                // Include non-text messages (stickers/images) so message_count
                // and last_message_ts stay accurate. Empty body is allowed.
                let msg_id = m
                    .get("id")
                    .cloned()
                    .or_else(|| m.get("dataId").cloned())
                    .and_then(|v| v.as_str().map(|s| s.to_string()))
                    .unwrap_or_default();
                if msg_id.is_empty() {
                    return None;
                }
                // Resolve sender: full-scan uses fromName/from; DOM rows use author.
                let sender = m
                    .get("fromName")
                    .cloned()
                    .or_else(|| m.get("from").cloned())
                    .or_else(|| m.get("author").cloned());
                let sender_jid = m
                    .get("from")
                    .cloned()
                    .or_else(|| m.get("author").cloned())
                    .or_else(|| m.get("participant").cloned());
                // Resolve timestamp: full-scan has numeric timestamp;
                // DOM rows may carry a string preTimestamp that needs parsing.
                let timestamp = m
                    .get("timestamp")
                    .and_then(|v| v.as_i64())
                    .or_else(|| m.get("preTimestamp").and_then(|v| v.as_i64()))
                    .unwrap_or(0);
                // Per-row source tag (issue #1376): rows that picked up their
                // body from the DOM scrape get tagged `cdp-dom` so the
                // structured store can distinguish DOM-sourced text from
                // IDB-sourced metadata. `merge_dom_into_snapshot` stamps
                // `bodySource = "dom"` (IDB row patched with DOM body) and
                // `"dom-only"` (DOM row with no IDB peer); both cases fall
                // back to `cdp-dom`. Everything else inherits the caller's
                // tag (full-scan = `cdp-indexeddb`, fast-tick = `cdp-dom`).
                let row_source = m
                    .get("bodySource")
                    .and_then(|v| v.as_str())
                    .filter(|s| matches!(*s, "dom" | "dom-only"))
                    .map(|_| "cdp-dom")
                    .unwrap_or(source);
                Some(json!({
                    "message_id": msg_id,
                    "chat_id": chat_id,
                    "sender": sender.unwrap_or(Value::Null),
                    "sender_jid": sender_jid.unwrap_or(Value::Null),
                    "from_me": m.get("fromMe").and_then(|v| v.as_bool()).unwrap_or(false),
                    "body": body,
                    "timestamp": timestamp,
                    "message_type": m.get("type").cloned().unwrap_or(Value::Null),
                    "source": row_source,
                }))
            }).collect

