                "me".to_string()
            } else {
                // Prefer the resolved display name; fall back to raw JID
                // (the "from" field), then "?".
                m.get("fromName")
                    .and_then(|v| v.as_str())
                    .filter(|s| !s.is_empty())
                    .or_else(|| m.get("from").and_then(|v| v.as_str()))
                    .filter(|s| !s.is_empty())
                    .unwrap_or("?")
                    .to_string()
            };
            let body = m
                .get("body")
                .and_then(|v| v.as_str())
                .unwrap_or("")
                .replace(['\r', '\n'], " ");
            let type_ = m
                .get("type")
                .and_then(|v| v.as_str())
                .filter(|t| *t != "chat" && !t.is_empty())
                .map(|t| format!(" [{t}]"))
                .unwrap_or_default();
            format!("[{hhmm}] {who}{type_}: {body}")
        })
        .collect::<Vec<_>>().join

